const http = require('http');

function mcpRequest(host, port, body, sessionId) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const headers = { 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream', 'Content-Length': Buffer.byteLength(data) };
    if (sessionId) headers['Mcp-Session-Id'] = sessionId;
    const req = http.request({ hostname: host, port, path: '/mcp', method: 'POST', headers }, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        const lines = body.split('\n');
        let jsonData = '';
        for (const line of lines) { if (line.startsWith('data: ')) jsonData = line.substring(6); }
        resolve({ status: res.statusCode, headers: res.headers, body: jsonData || body });
      });
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

async function callMcpTool(host, port, toolName, toolArgs) {
  const init = await mcpRequest(host, port, { jsonrpc: '2.0', id: 1, method: 'initialize', params: { protocolVersion: '2024-11-05', capabilities: {}, clientInfo: { name: 'n8n-workflow', version: '1.0' } } });
  const sid = init.headers['mcp-session-id'];
  await mcpRequest(host, port, { jsonrpc: '2.0', method: 'notifications/initialized' }, sid);
  const result = await mcpRequest(host, port, { jsonrpc: '2.0', id: 3, method: 'tools/call', params: { name: toolName, arguments: toolArgs } }, sid);
  const parsed = JSON.parse(result.body);
  return parsed.result?.content?.[0]?.text || 'Error: ' + JSON.stringify(parsed.error);
}

const j = $input.first().json;
const host = j.mcpHost;
const port = parseInt(j.mcpPort, 10);
const mcpOutput = await callMcpTool(host, port, j.toolName, { namespace: j.namespace });
return [{ json: { ...j, mcpOutput } }];

const http = require('http');
const input = $input.first().json;
const litellmHost = input.litellmHost;
const litellmPort = parseInt(input.litellmPort, 10);
const toolName = input.toolName;
const namespace = input.namespace;
const mcpOutput = input.mcpOutput || '';
const systemPrompt = 'You are an expert Red Hat OpenShift / Kubernetes administrator. Analyze the output from the MCP tool "' + toolName + '" for namespace "' + namespace + '".\n\nProvide a structured analysis in HTML (inline styles only, no external CSS):\n1. Summary: 2-3 sentence overview of the current state\n2. Formatted Table: Present the key data in a clean HTML table with relevant columns\n3. Health Assessment: Overall status (Healthy / Warning / Critical) with justification\n4. Observations & Recommendations: Key findings and actionable recommendations\n\nKeep the analysis professional, concise, and actionable. Use Red Hat brand colors (#EE0000 for accents) in the HTML styling.';
const requestBody = JSON.stringify({
  model: 'granite',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: mcpOutput }
  ],
  temperature: 0.3,
  max_tokens: 4096
});
return new Promise((resolve, reject) => {
  const req = http.request({
    hostname: litellmHost,
    port: litellmPort,
    path: '/v1/chat/completions',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(requestBody)
    }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      try {
        const parsed = JSON.parse(data);
        const aiAnalysis = parsed.choices?.[0]?.message?.content || 'AI analysis unavailable';
        const model = parsed.model || 'granite';
        resolve([{ json: { ...input, aiAnalysis, aiModel: model } }]);
      } catch (e) {
        resolve([{ json: { ...input, aiAnalysis: 'AI analysis failed: ' + e.message, aiModel: 'error' } }]);
      }
    });
  });
  req.on('error', (e) => {
    resolve([{ json: { ...input, aiAnalysis: 'AI service unavailable: ' + e.message, aiModel: 'unreachable' } }]);
  });
  req.write(requestBody);
  req.end();
});

